const etfs = [
  {
    isin: 'IE00BKM4GZ66',
    symbol: 'IS3N.DE',
    name: 'iShares Core MSCI EM IMI UCITS ETF Acc'
  },
  {
    isin: 'IE00B1YZSC51',
    symbol: 'IQQY.DE',
    name: 'iShares Core MSCI Europe UCITS ETF Dist'
  },
  {
    isin: 'IE00B52MJY50',
    symbol: 'SXR1.DE',
    name: 'iShares Core MSCI Pacific ex Japan UCITS ETF Acc'
  },
  {
    isin: 'IE00B4L5Y983',
    symbol: 'EUNL.DE',
    name: 'iShares Core MSCI World UCITS ETF Acc'
  }
];

const thresholds = {
  weeklyDropPercent: -5,
  monthlyDropPercent: -10,
  weeklyRisePercent: 5
};

function pctChange(current, old) {
  if (!current || !old) return null;
  return Number((((current - old) / old) * 100).toFixed(2));
}

function getCloseAtOffset(closes, offsetFromEnd) {
  const valid = closes.filter(v => typeof v === 'number');
  if (valid.length <= offsetFromEnd) return null;
  return valid[valid.length - 1 - offsetFromEnd];
}

const results = [];

for (const etf of etfs) {
  try {
    const url = `https://query1.finance.yahoo.com/v8/finance/chart/${etf.symbol}?range=1mo&interval=1d`;

    const response = await this.helpers.httpRequest({
      method: 'GET',
      url,
      json: true,
      headers: {
        'User-Agent': 'Mozilla/5.0 n8n ETF Monitor'
      }
    });

    const chart = response?.chart?.result?.[0];
    const closes = chart?.indicators?.quote?.[0]?.close || [];
    const timestamps = chart?.timestamp || [];

    const current = getCloseAtOffset(closes, 0);
    const price7d = getCloseAtOffset(closes, 5);
    const price30d = getCloseAtOffset(closes, 20);

    const weeklyChange = pctChange(current, price7d);
    const monthlyChange = pctChange(current, price30d);

    const alerts = [];

    if (weeklyChange !== null && weeklyChange <= thresholds.weeklyDropPercent) {
      alerts.push(`Wochenverlust ${weeklyChange}%`);
    }

    if (monthlyChange !== null && monthlyChange <= thresholds.monthlyDropPercent) {
      alerts.push(`Monatsverlust ${monthlyChange}%`);
    }

    if (weeklyChange !== null && weeklyChange >= thresholds.weeklyRisePercent) {
      alerts.push(`Wochenanstieg ${weeklyChange}%`);
    }

    results.push({
      json: {
        isin: etf.isin,
        symbol: etf.symbol,
        name: etf.name,
        currentPrice: current,
        currency: chart?.meta?.currency || 'EUR',
        weeklyChangePercent: weeklyChange,
        monthlyChangePercent: monthlyChange,
        alert: alerts.length > 0,
        alerts: alerts.join(', ') || 'Keine Auffälligkeit',
        checkedAt: new Date().toISOString()
      }
    });
  } catch (error) {
    results.push({
      json: {
        isin: etf.isin,
        symbol: etf.symbol,
        name: etf.name,
        currentPrice: null,
        weeklyChangePercent: null,
        monthlyChangePercent: null,
        alert: true,
        alerts: `Fehler beim Abruf: ${error.message}`,
        checkedAt: new Date().toISOString()
      }
    });
  }
}

return results;

const etfs = [
  {
    isin: 'IE00BKM4GZ66',
    symbol: 'IS3N.DE',
    name: 'iShares Core MSCI EM IMI UCITS ETF Acc'
  },
  {
    isin: 'IE00B1YZSC51',
    symbol: 'IQQY.DE',
    name: 'iShares Core MSCI Europe UCITS ETF Dist'
  },
  {
    isin: 'IE00B52MJY50',
    symbol: 'SXR1.DE',
    name: 'iShares Core MSCI Pacific ex Japan UCITS ETF Acc'
  },
  {
    isin: 'IE00B4L5Y983',
    symbol: 'EUNL.DE',
    name: 'iShares Core MSCI World UCITS ETF Acc'
  }
];

const prompt = `
Du bist ein sachlicher ETF-Monitoring-Assistent.

Überwache wöchentlich folgende ETFs:

${etfs.map(etf => `- ${etf.name}
  ISIN: ${etf.isin}
  Börsensymbol: ${etf.symbol}`).join('\n\n')}

Aufgabe:
Erstelle eine kurze, verständliche Wochenbewertung der ETFs.

Bewerte insbesondere:
1. Auffällige Kursbewegungen
2. Starke Verluste oder starke Anstiege
3. Vergleich zwischen den ETFs
4. Ob ein ETF besonders beobachtet werden sollte
5. Eine kurze Zusammenfassung für einen privaten Anleger

Wichtig:
- Keine Anlageberatung geben.
- Keine Kauf- oder Verkaufsempfehlung aussprechen.
- Sachlich formulieren.
- Wenn Daten fehlen, klar darauf hinweisen.
- Ausgabe auf Deutsch.
- Kurz und übersichtlich schreiben.

Gewünschtes Ausgabeformat:

ETF-Wochenüberblick

1. Kurzfazit
2. Einzelbewertung je ETF
3. Auffälligkeiten
4. Beobachtungshinweise
5. Hinweis: Dies ist keine Anlageberatung.
`;

return [
  {
    json: {
      etfs,
      ai_prompt: prompt.trim(),
      created_at: new Date().toISOString()
    }
  }
];
